## Widget Examples

### Example 1: Static Widget (No API)

**Use case:** Calculator, Pomodoro Timer, Pixel Art

```typescript
import React, { useState } from 'react';
import { BaseWidget } from './BaseWidget';

export const CalculatorWidget: React.FC = () => {
  const [result, setResult] = useState<string>('0');

  const handleButtonClick = (value: string) => {
    // Calculator logic
    setResult(value);
  };

  return (
    <BaseWidget title="Calculator" icon="рҹ”ў">
      <div className="grid grid-cols-4 gap-2 p-2">
        {/* Calculator buttons */}
        <div className="col-span-4 bg-surface-light-elevated dark:bg-surface-dark p-3 rounded text-right text-2xl font-mono">
          {result}
        </div>
        {/* Number buttons... */}
      </div>
    </BaseWidget>
  );
};
